// TemplateSvgIcon.ets
//
// A model-friendly icon entry template for scaffolded HarmonyOS apps.
//
// Agent rules:
// - Keep the exported struct name as SvgIcon.
// - Keep the public API stable: variant, iconSize, color, and strokeWidth.
// - Prefer updating fileNameForVariant() and the matching rawfile assets instead of
// - hardcoding resource paths in page-level components.
// - Keep variant names generic so scaffold components are not tied to one product domain.
//
// Usage:
// - Replace the default rawfile mappings with your real icon assets.
// - Keep common variants such as home, explore, orders, rewards, search, profile,
// - back, add, remove, and favorite available when practical.
// - If the real project uses a different icon system, adapt this wrapper instead of
// - changing every caller.
//
// Notes:
// - The default rawfile names are placeholders from the bundled template assets.
// - color and strokeWidth are part of the stable template contract even when the
// - current rawfile-backed implementation does not apply tinting dynamically.
@Component
export struct SvgIcon {
  @Prop iconSize: number = 24;
  @Prop color: string = '#0F3329';
  @Prop strokeWidth: number = 2;
  @Prop variant: string = 'search';

  build() {
    Image($rawfile(this.fileNameForVariant()))
      .width(this.iconSize)
      .height(this.iconSize)
      .objectFit(ImageFit.Contain)
      .draggable(false)
  }

  private fileNameForVariant(): string {
    const v: string = this.variant;
    if (v === 'home') {
      return 'icon_首页-1.svg';
    } else if (v === 'explore' || v === 'menu') {
      return 'icon_菜单-1.svg';
    } else if (v === 'store' || v === 'stores') {
      return 'icon_门店-1.svg';
    } else if (v === 'rewards') {
      return 'icon_会员奖励-1.svg';
    } else if (v === 'orders' || v === 'history') {
      return 'icon_订单历史.svg';
    } else if (v === 'profile' || v === 'user') {
      return 'icon_进入我的账户.svg';
    } else if (v === 'cart') {
      return 'icon_查看购物车.svg';
    } else if (v === 'search') {
      return 'icon_搜索饮品.svg';
    } else if (v === 'trending' || v === 'reorder' || v === 'trendingUp') {
      return 'icon_一键复购最近订单.svg';
    } else if (v === 'add' || v === 'plus') {
      return 'icon_增加数量.svg';
    } else if (v === 'remove' || v === 'minus') {
      return 'icon_减少数量.svg';
    } else if (v === 'back') {
      return 'icon_返回上一页.svg';
    } else if (v === 'favorite' || v === 'heart') {
      return 'icon_收藏该饮品.svg';
    } else if (v === 'trash') {
      return 'icon_从购物车移除该商品.svg';
    } else if (v === 'info') {
      return 'icon_会员规则.svg';
    } else if (v === 'settings') {
      return 'icon_打开设置.svg';
    } else if (v === 'arrowRight' || v === 'chevronRight') {
      return 'icon_进入设置.svg';
    } else if (v === 'card') {
      return 'icon_支付方式图标.svg';
    } else if (v === 'placeholder' || v === 'cup') {
      return 'icon_拿铁饮品占位图.svg';
    }
    return 'icon_搜索饮品.svg';
  }
}

// TemplateTabTypes.ets
//
// Shared tab-level types for scaffold components that should not depend on
// controller or page implementation files.
//
// Agent rules:
// - Keep TabId stable unless the app's primary tab model changes.
// - Update Index.ets and BottomTabBar.ets together when changing tab ids.
//
// Usage:
// - Add lightweight tab/navigation unions here when multiple scaffold files
// - need the same tab contract.
export type TabId =
  | 'tab-home'
  | 'tab-explore'
  | 'tab-orders'
  | 'tab-rewards';

// TemplateBottomTabBar.ets
//
// A model-friendly BottomTabBar template for apps that use a fixed bottom tab shell.
//
// Agent rules:
// - Keep the exported struct name as BottomTabBar.
// - Keep the public API stable: activeTab and onTap.
// - Do not change the layout hierarchy unless the user explicitly asks.
// - Only replace tab ids, labels, icons, or theme tokens as needed.
// - Keep tab ids aligned with the shared TabId union used by Index.ets.
//
// Usage:
// - Update import paths to match your project structure.
// - Replace the TABS data with your real tab set.
// - Keep the component contract unchanged so Index.ets can keep using it safely.
//
// Notes:
// - This file is intentionally conservative. It is a fixed shell component, not a free-form page.
// - If the user asks for a different navigation pattern, change TemplateIndex.ets and this file together.

import { SvgIcon } from '../common/SvgIcon';
import { TabId } from '../common/TabTypes';
import { Theme } from '../common/Theme';

interface TabDescriptor {
  id: TabId;
  label: string;
  icon: string;
}

// Replace only the data below to match your real tabs.
const TABS: TabDescriptor[] = [
  { id: 'tab-home', label: 'Home', icon: 'home' },
  { id: 'tab-explore', label: 'Explore', icon: 'explore' },
  { id: 'tab-orders', label: 'Orders', icon: 'orders' },
  { id: 'tab-rewards', label: 'Rewards', icon: 'rewards' },
];

@Component
export struct BottomTabBar {
  @Prop activeTab: TabId;
  onTap: (tab: TabId) => void = () => {};

  build() {
    Row() {
      ForEach(TABS, (tab: TabDescriptor) => {
        Column() {
          SvgIcon({
            variant: tab.icon,
            iconSize: 24,
            color: this.activeTab === tab.id ? Theme.brandPrimary : Theme.textQuaternary,
            strokeWidth: 2
          })
          Text(tab.label)
            .fontSize(11)
            .fontWeight(FontWeight.Medium)
            .fontColor(this.activeTab === tab.id ? Theme.brandPrimary : Theme.textQuaternary)
            .margin({ top: 4 })
        }
        .id(tab.id)
        .padding({ left: 12, right: 12, top: 6, bottom: 6 })
        .onClick(() => this.onTap(tab.id))
        .layoutWeight(1)
        .alignItems(HorizontalAlign.Center)
      }, (tab: TabDescriptor) => tab.id)
    }
    .width('100%')
    .height(Theme.bottomTabHeight)
    .padding({ bottom: 8 })
    .backgroundColor('rgba(255,255,255,0.94)')
    .border({ width: { top: 1 }, color: { top: Theme.borderSoft } })
    .justifyContent(FlexAlign.SpaceAround)
    .alignItems(VerticalAlign.Center)
  }
}

